// restore.go
package addons
import (
	"context"
	"fmt"
	"net/http"
	apiv3 "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/openmeter/productcatalog/addon"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/models"
)
type (
	RestoreAddonRequest  = addon.RestoreAddonInput
	RestoreAddonResponse = apiv3.Addon
	RestoreAddonParams   = string
	RestoreAddonHandler  httptransport.HandlerWithArgs[RestoreAddonRequest, RestoreAddonResponse, string]
)
func (h *handler) RestoreAddon() RestoreAddonHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, addonID RestoreAddonParams) (RestoreAddonRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return RestoreAddonRequest{}, err }
			return RestoreAddonRequest{NamespacedID: models.NamespacedID{Namespace: ns, ID: addonID}}, nil
		},
		func(ctx context.Context, request RestoreAddonRequest) (RestoreAddonResponse, error) {
			a, err := h.service.RestoreAddon(ctx, request)
			if err != nil { return RestoreAddonResponse{}, err }
			if a == nil { return RestoreAddonResponse{}, fmt.Errorf("failed to restore add-on") }
			return ToAPIAddon(*a)
		},
		commonhttp.JSONResponseEncoderWithStatus[RestoreAddonResponse](http.StatusOK),
		httptransport.AppendOptions(h.options,
			httptransport.WithOperationName("restore-addon"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}

