// validate.go:
package billingprofiles
import (
	"context"
	"net/http"
	api "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/openmeter/billing"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/models"
)
type (
	ValidateBillingProfileRequest  = billing.GetProfileInput
	ValidateBillingProfileResponse = api.BillingProfile
	ValidateBillingProfileParams   = string
	ValidateBillingProfileHandler  httptransport.HandlerWithArgs[ValidateBillingProfileRequest, ValidateBillingProfileResponse, string]
)
func (h *handler) ValidateBillingProfile() ValidateBillingProfileHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, profileID string) (ValidateBillingProfileRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return ValidateBillingProfileRequest{}, err }
			return ValidateBillingProfileRequest{
				Profile: billing.ProfileID(models.NamespacedID{Namespace: ns, ID: profileID}),
				Expand: billing.ProfileExpand{Apps: true},
			}, nil
		},
		func(ctx context.Context, request ValidateBillingProfileRequest) (ValidateBillingProfileResponse, error) {
			profile, err := h.service.GetProfile(ctx, request)
			if err != nil { return ValidateBillingProfileResponse{}, err }
			return ToAPIBillingProfile(*profile)
		},
		commonhttp.JSONResponseEncoderWithStatus[ValidateBillingProfileResponse](http.StatusOK),
		httptransport.AppendOptions(h.options,
			httptransport.WithOperationName("validate-billing-profile"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
			httptransport.WithErrorEncoder(errorEncoder()), // always chain both
		)...,
	)
}

