func fromAPISubjectFilter(ctx context.Context, f *api.StringFieldFilter) (*filter.FilterString, error) {
	if f == nil {
		return nil, nil
	}
	var values []string
	if f.Eq != nil {
		values = append(values, *f.Eq)
	}
	if len(values) == 0 {
		return nil, nil
	}
	return &filter.FilterString{In: &values}, nil
}
